void findLargestOddSubstring(string num) {
    int i;

    // Traverse from end to find the last odd digit
    for (i = num.length() - 1; i >= 0; i--) {
        if ((num[i] - '0') % 2 != 0) {
            break;
        }
    }

    if (i == -1) {
        // No odd digit found
        cout << "-1" << endl;
    } else {
        // Output substring from start to that odd digit
        cout << num.substr(0, i + 1) << endl;
    }
}

