void findLargestOddSubstring(char num[]) {
    int len = strlen(num);
    int i;

    // Find the last odd digit from the right
    for (i = len - 1; i >= 0; i--) {
        if ((num[i] - '0') % 2 != 0) {
            break;
        }
    }

    if (i == -1) {
        // No odd digit found
        printf("-1\n");
    } else {
        // Print substring from start to i
        for (int j = 0; j <= i; j++) {
            printf("%c", num[j]);
        }
        printf("\n");
    }
}

